import React, { useState, useEffect } from 'react';
import { Navigate } from 'react-router-dom';
import MasterLayout from '../layouts/admin/MasterLayout';
import axios from 'axios';
import Swal from 'sweetalert2';

function AdminPrivateRoute()
{
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const [loading, setLoading] = useState(true);

    useEffect(() =>
    {
        let isMounted = true;
        // This API call checks with your Laravel backend if the token is valid.
        axios.get('/api/user').then(res =>
        {
            if (isMounted)
            {
                if (res.status === 200)
                {
                    setIsAuthenticated(true);
                }
                setLoading(false);
            }
        }).catch(err =>
        {
            if (isMounted)
            {
                // If the API call returns an error (like 401 Unauthorized),
                // it means the user is not authenticated.
                setIsAuthenticated(false);
                setLoading(false);
            }
        });

        // Cleanup function to avoid state updates on an unmounted component.
        return () => { isMounted = false; };
    }, []);



    //deal with 401 error message
    axios.interceptors.response.use(undefined, function axiosRetryInterceptor(err)
    {
        if (err.response.status === 401)
        {
            Swal("Unauthorized", err.response.data.message, "Warning!");
            history.push("/");
        }
        return Promise.reject(err);

    });



    if (loading)
    {
        // You can replace this with a more sophisticated spinner component.
        return <h1>Loading...</h1>;
    }

    return isAuthenticated ? <MasterLayout /> : <Navigate to="/login" replace />;
}

export default AdminPrivateRoute;
